const o=document.getElementById("navbar"),c=document.getElementById("hamburger"),n=document.getElementById("navLinks");window.addEventListener("scroll",()=>{o.classList.toggle("scrolled",window.scrollY>20)});c.addEventListener("click",()=>n.classList.toggle("open"));n.querySelectorAll("a").forEach(t=>{t.addEventListener("click",()=>n.classList.remove("open"))});const l=document.querySelectorAll("section[id]"),r=document.querySelectorAll(".nav-links a");window.addEventListener("scroll",()=>{let t="";l.forEach(e=>{window.scrollY>=e.offsetTop-130&&(t=e.id)}),r.forEach(e=>{e.style.color=e.getAttribute("href")===`/#${t}`?"var(--accent)":""})});
